struct FrameReader {
    child: Child,
    frame_index: u64,
    width: usize,
    height: usize,
    frame_bytes: usize,
    done: bool,
}
impl FrameReader {
    fn new(child: Child, width: usize, height: usize) -> Self {
        Self {
            child,
            frame_index: 0,
            width,
            height,
            frame_bytes: width * height * 3,
            done: false,
        }
    }
}
